onClick:
{{
  createTrip.run()
    .then(() => {
      // 1. Show Success Message
      showAlert('Trip Created Successfully!', 'success');

      // 2. Refresh the UI
      getTrips.run();           // Refresh the Active Trips table
      getPendingInvoices.run(); // Remove the used invoices from the pending list

      // 3. Optional: Close the modal if you are using one
      closeModal('mdlCreateTrip'); 
    })
    .catch((error) => {
      // Show exactly why it failed (e.g., "Invoices already assigned")
      showAlert('Creation Failed: ' + error.message, 'error');
    });
}}
